public String zipZap(String str)
{
    int length = str.length() - 2;
    for (int i = 0; i < length; i++)
    {
        String sub = str.substring(i, i + 2);
        if (sub.startsWith("z") && sub.endsWith("p"))
        {
            sub = str.substring(0, i) + str.substring(i + 2);
        }
    }
    return sub;
}

