public String[] fizzBuzz(int start, int end)
{
    String[] str = new String[end - start];
        int count = 0;
        for(int i = start; i < end ; i++)
        {

            str[count] = String.valueOf(i);


            if(i % 3 == 0)
            {
            str[count] = new String("Fizz");
            }
            if(i % 5 == 0)
            {
            str[count] = new String("Buzz");
            }

            if(i%3==0 && i%5==0)
            {
            str[count] = new String("FizzBuzz");
            }
            count++;
        }
    return str;
}

