public String atFirst(String str)
{
    String string = "";
    int size = str.length();
    if (size < 2)
    {
        string = str.substring(0) + "@";
        if (size < 1)
        {
            string = "@@";
        }
    }
    else
    {
        string = str.substring(0, 2);
    }
    return string;
}

